SELECT pd.peid, af.bloc_name
FROM population_data pd
JOIN affinity_blocs af ON pd.affinity_bloc = af.bloc_name;

SELECT group_name
FROM people_groups
WHERE population_estimate > 100000000;

SELECT bloc_name, AVG(population_estimate) AS average_population
FROM affinity_blocs
GROUP BY bloc_name;

SELECT COUNT(DISTINCT people_group) AS number_of_groups
FROM population_data
WHERE people_cluster = 'Deaf';

SELECT peid, affinity_bloc, people_group, population, addition_date
FROM population_data
WHERE people_group = 'Arab' AND affinity_bloc = 'Deaf Peoples';

SELECT people_group, population, addition_reasons
FROM population_data
WHERE global_status = 1 AND population > 1000000;

SELECT DISTINCT people_group
FROM population_data
WHERE affinity_bloc = 'specific_affinity_bloc';

SELECT group_name
FROM people_groups
ORDER BY last_updated DESC;

SELECT country_name, population
FROM countries
ORDER BY country_name;
